#' LASSO Logistic Regression
#'
#' Performs LASSO-penalized logistic regression for variable selection in 
#' binary
#' classification problems. Ideal for diagnostic pathology studies that build
#' classifiers (e.g., tumor type A vs B) with automatic feature selection.
#' 
#'
#' @examples
#' \donttest{
#' lassologistic(data = data, outcome = "diagnosis",
#'     outcomeLevel = "PanNEC", explanatory = vars(p53, Rb1, Ki67, SSTR2A))
#'}
#' @param data The data as a data frame.
#' @param outcome Binary outcome variable to classify. Can be factor or
#'   numeric with exactly two observed values.
#' @param outcomeLevel Level of outcome considered as the positive class
#'   (event). For factor outcomes, if left empty the second level is used.
#' @param explanatory Variables to be considered for selection. At least 2
#'   required. Constant variables are removed automatically.
#' @param penalty Type of regularization penalty. LASSO (L1) produces sparse
#'   models by setting coefficients to zero. Ridge (L2) shrinks but retains all.
#'   Elastic Net combines both.
#' @param alpha Mixing parameter for elastic net. Only used when penalty is
#'   elasticnet.
#' @param lambda Method for selecting the optimal lambda from
#'   cross-validation. 1SE rule tends to select fewer variables (more
#'   conservative).
#' @param nfolds Number of folds for cross-validation. Automatically reduced
#'   when sample size is limited.
#' @param random_seed Random seed for reproducible cross-validation fold
#'   assignment.
#' @param standardize Whether to standardize predictor variables before
#'   fitting.
#' @param suitabilityCheck Check sample size, events-per-variable ratio,
#'   multicollinearity, and whether regularization is needed.
#' @param bootstrapValidation Perform bootstrap optimism-corrected validation
#'   (Harrell method). Reports corrected AUC, calibration slope, and Brier
#'   score.
#' @param bootstrapN Number of bootstrap iterations for internal validation.
#' @param cv_plot Show cross-validation deviance vs lambda plot.
#' @param coef_plot Show bar plot of selected variable coefficients.
#' @param roc_plot Show ROC curve with AUC and confidence interval.
#' @param scoringSystem Convert model coefficients to an integer-point scoring
#'   system. Multiple methods available following published standards.
#' @param scoringMethod Method for converting regression coefficients to
#'   integer points. Beta10: multiply by 10, round (Zhang et al. 2017).
#'   Schneeweiss: divide by smallest absolute coefficient (Mehta et al. 2016).
#'   Sullivan: reference-variable scaling (Sullivan et al. 2004, Framingham
#'   method). Compare: generate all three and show performance comparison.
#' @param scoringMaxPoints Maximum points assigned to the strongest predictor
#'   (Beta10 method).
#' @param scoreLookupTable Generate a lookup table mapping each possible total
#'   score to predicted probability of the positive class.
#' @param showSummary Display a natural-language summary of the main results.
#' @param showExplanations Display explanations of LASSO logistic regression
#'   methodology.
#' @param showMethodologyNotes Show technical notes about regularization and
#'   validation.
#' @param includeClinicalGuidance Include guidance for clinical interpretation
#'   of results.
#' @param showVariableImportance Display variable importance rankings across
#'   lambda values.
#' @param showModelComparison Compare LASSO vs standard logistic using
#'   selected variables.
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$todo} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$suitabilityReport} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$modelSummary} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$coefficients} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$performance} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$scoringTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$scoringPerformance} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$methodComparison} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$lookupTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$validationTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$cv_plot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$coef_plot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$roc_plot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$predictions} \tab \tab \tab \tab \tab an output \cr
#'   \code{results$summaryText} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$lassoExplanation} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$methodologyNotes} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$clinicalGuidance} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$variableImportance} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$modelComparison} \tab \tab \tab \tab \tab a table \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$modelSummary$asDF}
#'
#' \code{as.data.frame(results$modelSummary)}
#'
#' @export
lassologistic <- function(
    data,
    outcome,
    outcomeLevel,
    explanatory,
    penalty = "lasso",
    alpha = 0.5,
    lambda = "lambda.1se",
    nfolds = 10,
    random_seed = 123456,
    standardize = TRUE,
    suitabilityCheck = TRUE,
    bootstrapValidation = FALSE,
    bootstrapN = 200,
    cv_plot = TRUE,
    coef_plot = TRUE,
    roc_plot = TRUE,
    scoringSystem = FALSE,
    scoringMethod = "schneeweiss",
    scoringMaxPoints = 10,
    scoreLookupTable = TRUE,
    showSummary = FALSE,
    showExplanations = FALSE,
    showMethodologyNotes = FALSE,
    includeClinicalGuidance = FALSE,
    showVariableImportance = FALSE,
    showModelComparison = FALSE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("lassologistic requires jmvcore to be installed (restart may be required)")

    if ( ! missing(outcome)) outcome <- jmvcore::resolveQuo(jmvcore::enquo(outcome))
    if ( ! missing(explanatory)) explanatory <- jmvcore::resolveQuo(jmvcore::enquo(explanatory))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(outcome), outcome, NULL),
            `if`( ! missing(explanatory), explanatory, NULL))


    options <- lassologisticOptions$new(
        outcome = outcome,
        outcomeLevel = outcomeLevel,
        explanatory = explanatory,
        penalty = penalty,
        alpha = alpha,
        lambda = lambda,
        nfolds = nfolds,
        random_seed = random_seed,
        standardize = standardize,
        suitabilityCheck = suitabilityCheck,
        bootstrapValidation = bootstrapValidation,
        bootstrapN = bootstrapN,
        cv_plot = cv_plot,
        coef_plot = coef_plot,
        roc_plot = roc_plot,
        scoringSystem = scoringSystem,
        scoringMethod = scoringMethod,
        scoringMaxPoints = scoringMaxPoints,
        scoreLookupTable = scoreLookupTable,
        showSummary = showSummary,
        showExplanations = showExplanations,
        showMethodologyNotes = showMethodologyNotes,
        includeClinicalGuidance = includeClinicalGuidance,
        showVariableImportance = showVariableImportance,
        showModelComparison = showModelComparison)

    analysis <- lassologisticClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

